export default function GpuChip({
  className = "w-100",
  colors,
  float = false,
}: {
  className?: string
  colors?: Partial<GpuChipColors>
  float?: boolean
}) {
  const c = { ...COLORS, ...colors }
  const uid = useId()
  const gradId = `${uid}-paint0_linear_2012_1943`

  return (
    <div>
      <svg
        className={className}
        viewBox="0 0 464 362"
        fill="none"
        preserveAspectRatio="xMidYMid meet"
      >
        <defs>
          <linearGradient
            id={gradId}
            x1="218.992"
            y1="78.1225"
            x2="68.2571"
            y2="170.679"
            gradientUnits="userSpaceOnUse"
          >
            <stop stopColor={c.gradientFrom} />
            <stop offset="1" stopColor={c.gradientTo} />
          </linearGradient>
        </defs>

        {ROWS.map((row, rowIndex) => (
          <motion.g
            key={rowIndex}
            initial={{ opacity: 0, scale: 0.55, y: -6 }}
            // animate={{ opacity: row.opacity, scale: 1, y: 0 }}
            whileInView={{ opacity: row.opacity, scale: 1, y: 0 }}
            viewport={{ once: true, amount: "some" }}
            transition={{
              duration: 0.6,
              delay: rowIndex * 0.055,
              ease: [0.22, 1, 0.36, 1],
            }}
            style={{
              transformBox: "fill-box",
              transformOrigin: "center",
            }}
          >
            {COLS.map((x, colIndex) => (
              <g key={colIndex}>
                <circle cx={x} cy={row.y} r="2.76758" fill={c.dot} />
                <circle cx={x} cy={row.y} r="1.66055" fill={c.dotInner} />
              </g>
            ))}
          </motion.g>
        ))}

        <motion.g
          animate={float && { y: [0, -10, 0] }}
          transition={{
            duration: 5,
            repeat: Infinity,
            repeatType: "reverse",
            ease: "easeInOut",
          }}
        >
          <motion.path
            d="M415.924 160L230.892 263.235L47.4236 159.5L230.892 53L415.924 160Z"
            fill={`url(#${gradId})`}
            stroke={c.stroke}
            strokeWidth="2"
            animate={{ strokeOpacity: [0.49, 0.9, 0.49] }}
            transition={{ duration: 3.5, repeat: Infinity, ease: "easeInOut" }}
          />
          <path
            d="M230.892 70.1891L81.9236 158L230.892 242.08L383.924 158L230.892 70.1891Z"
            stroke={c.stroke}
            strokeWidth="2"
          />
          <path d={CHIP_TEXT_TOP} fill={c.text} fillOpacity="0.6" />
          <path d={CHIP_TEXT_BOTTOM} fill={c.text} fillOpacity="0.31" />
          <rect
            width="212.424"
            height="17.0461"
            transform="matrix(0.8709 0.49146 0 1 46.4236 159)"
            fill={c.stroke}
          />
          <rect
            width="212.424"
            height="18.0488"
            transform="matrix(0.8709 -0.49146 0 1 231.424 263.398)"
            fill={c.accentBar}
          />
        </motion.g>
      </svg>
    </div>
  )
}
